// ════════════════════════════════════════════════════════
// COMMITTER v3 — accepte {operations, annee, confirmation:OUI}
// Applique les ops via applyOp() puis POST save_data.php
// ════════════════════════════════════════════════════════
let input;
try {
  input = typeof query === 'string' ? JSON.parse(query) : query;
} catch (e) {
  return JSON.stringify({ error: 'JSON invalide : ' + e.message });
}

// ── GARDE 1 : confirmation = "OUI" ──
if (!input.confirmation || String(input.confirmation).toUpperCase().trim() !== 'OUI') {
  return JSON.stringify({ error: 'REFUS : le paramètre `confirmation` doit être la chaîne "OUI". L\'utilisateur doit taper OUI dans le chat avant que tu appelles cet outil.' });
}

// ── GARDE 2 : dernier message utilisateur contient "OUI" ──
const normalized = $('Normalize Input').first().json;
const lastUserMsg = (normalized.question || '').toUpperCase();
if (!/\bOUI\b/.test(lastUserMsg)) {
  return JSON.stringify({ error: 'REFUS : le dernier message utilisateur ne contient pas "OUI". Demande confirmation avant de relancer.' });
}

// ── GARDE 3 : opérations présentes ──
const operations = Array.isArray(input.operations) ? input.operations : [];
if (operations.length === 0) {
  return JSON.stringify({ error: 'REFUS : aucune opération fournie. Renvoie le même tableau operations utilisé pour la simulation.' });
}
const anneeTarget = Number(input.annee) || new Date().getFullYear();

// ── finance_data depuis la requête ──
if (!normalized.finance_data) {
  return JSON.stringify({ error: 'finance_data absent de la requête. L\'utilisateur doit relancer depuis l\'interface web.' });
}
const financeData = JSON.parse(JSON.stringify(normalized.finance_data));

function applyOp(financeData, op, anneeTarget) {
  const a = Number(op.annee || anneeTarget);
  const y = financeData.donneesAnnuelles && financeData.donneesAnnuelles[a];
  const log = { op: op.type };
  try {
    switch (op.type) {
      // ═══ REVENUS ═══
      case 'set_revenu': {
        if (!y || !y.revenus || !y.revenus[op.key]) { log.status = 'skip'; log.reason = 'année ou clé absente'; break; }
        const old = y.revenus[op.key].base;
        y.revenus[op.key].base = Number(op.base);
        log.key = op.key; log.avant = old; log.apres = Number(op.base);
        break;
      }
      case 'add_revenu': {
        if (!y) { log.status = 'skip'; log.reason = 'année absente'; break; }
        if (!y.revenus) y.revenus = {};
        if (y.revenus[op.key]) { log.status = 'skip'; log.reason = 'clé existe déjà'; break; }
        y.revenus[op.key] = { label: String(op.label || op.key), base: Number(op.base || 0), showExceptions: false, exceptions: [] };
        log.key = op.key; log.created = true; break;
      }
      case 'remove_revenu': {
        if (!y || !y.revenus || !y.revenus[op.key]) { log.status = 'skip'; log.reason = 'clé absente'; break; }
        delete y.revenus[op.key]; log.key = op.key; log.removed = true; break;
      }
      case 'rename_revenu': {
        if (!y || !y.revenus || !y.revenus[op.key]) { log.status = 'skip'; log.reason = 'clé absente'; break; }
        const old = y.revenus[op.key].label;
        y.revenus[op.key].label = String(op.label);
        log.key = op.key; log.avant = old; log.apres = String(op.label); break;
      }
      case 'add_revenu_exception': {
        if (!y || !y.revenus || !y.revenus[op.key]) { log.status = 'skip'; log.reason = 'clé absente'; break; }
        if (!Array.isArray(y.revenus[op.key].exceptions)) y.revenus[op.key].exceptions = [];
        const id = Date.now() + Math.floor(Math.random() * 1000);
        y.revenus[op.key].exceptions.push({ id, moisDebut: Number(op.moisDebut), moisFin: Number(op.moisFin), nouvelleValeur: Number(op.nouvelleValeur) });
        y.revenus[op.key].showExceptions = true;
        log.key = op.key; log.id = id; break;
      }
      case 'remove_revenu_exception': {
        if (!y || !y.revenus || !y.revenus[op.key]) { log.status = 'skip'; log.reason = 'clé absente'; break; }
        const before = (y.revenus[op.key].exceptions || []).length;
        y.revenus[op.key].exceptions = (y.revenus[op.key].exceptions || []).filter(e => Number(e.id) !== Number(op.id));
        log.key = op.key; log.supprimees = before - y.revenus[op.key].exceptions.length; break;
      }

      // ═══ CHARGES FIXES ═══
      case 'set_charge_fixe': {
        if (!y || !y.chargesFixes || !y.chargesFixes[op.key]) { log.status = 'skip'; log.reason = 'année ou clé absente'; break; }
        const old = y.chargesFixes[op.key].valeur;
        y.chargesFixes[op.key].valeur = Number(op.valeur);
        log.key = op.key; log.avant = old; log.apres = Number(op.valeur); break;
      }
      case 'add_charge_fixe': {
        if (!y) { log.status = 'skip'; log.reason = 'année absente'; break; }
        if (!y.chargesFixes) y.chargesFixes = {};
        if (y.chargesFixes[op.key]) { log.status = 'skip'; log.reason = 'clé existe déjà'; break; }
        y.chargesFixes[op.key] = { label: String(op.label || op.key), valeur: Number(op.valeur || 0), showExceptions: false, exceptions: [], montantPaye: 0, paye: false };
        log.key = op.key; log.created = true; break;
      }
      case 'remove_charge_fixe': {
        if (!y || !y.chargesFixes || !y.chargesFixes[op.key]) { log.status = 'skip'; log.reason = 'clé absente'; break; }
        delete y.chargesFixes[op.key]; log.key = op.key; log.removed = true; break;
      }
      case 'rename_charge_fixe': {
        if (!y || !y.chargesFixes || !y.chargesFixes[op.key]) { log.status = 'skip'; log.reason = 'clé absente'; break; }
        const old = y.chargesFixes[op.key].label;
        y.chargesFixes[op.key].label = String(op.label);
        log.key = op.key; log.avant = old; log.apres = String(op.label); break;
      }
      case 'add_charge_fixe_exception': {
        if (!y || !y.chargesFixes || !y.chargesFixes[op.key]) { log.status = 'skip'; log.reason = 'clé absente'; break; }
        if (!Array.isArray(y.chargesFixes[op.key].exceptions)) y.chargesFixes[op.key].exceptions = [];
        const id = Date.now() + Math.floor(Math.random() * 1000);
        y.chargesFixes[op.key].exceptions.push({ id, moisDebut: Number(op.moisDebut), moisFin: Number(op.moisFin), nouvelleValeur: Number(op.nouvelleValeur) });
        y.chargesFixes[op.key].showExceptions = true;
        log.key = op.key; log.id = id; break;
      }
      case 'remove_charge_fixe_exception': {
        if (!y || !y.chargesFixes || !y.chargesFixes[op.key]) { log.status = 'skip'; log.reason = 'clé absente'; break; }
        const before = (y.chargesFixes[op.key].exceptions || []).length;
        y.chargesFixes[op.key].exceptions = (y.chargesFixes[op.key].exceptions || []).filter(e => Number(e.id) !== Number(op.id));
        log.key = op.key; log.supprimees = before - y.chargesFixes[op.key].exceptions.length; break;
      }

      // ═══ CHARGES VARIABLES ═══
      case 'set_charge_variable': {
        if (!y || !y.chargesVariables || !y.chargesVariables[op.key]) { log.status = 'skip'; log.reason = 'année ou clé absente'; break; }
        const old = y.chargesVariables[op.key].valeur;
        y.chargesVariables[op.key].valeur = Number(op.valeur);
        log.key = op.key; log.avant = old; log.apres = Number(op.valeur); break;
      }
      case 'add_charge_variable': {
        if (!y) { log.status = 'skip'; log.reason = 'année absente'; break; }
        if (!y.chargesVariables) y.chargesVariables = {};
        if (y.chargesVariables[op.key]) { log.status = 'skip'; log.reason = 'clé existe déjà'; break; }
        const periode = (op.periode === 'semaine' || op.periode === 'mois') ? op.periode : 'mois';
        y.chargesVariables[op.key] = { label: String(op.label || op.key), valeur: Number(op.valeur || 0), periode, showDetails: false, details: [] };
        log.key = op.key; log.created = true; break;
      }
      case 'remove_charge_variable': {
        if (!y || !y.chargesVariables || !y.chargesVariables[op.key]) { log.status = 'skip'; log.reason = 'clé absente'; break; }
        delete y.chargesVariables[op.key]; log.key = op.key; log.removed = true; break;
      }
      case 'set_charge_variable_periode': {
        if (!y || !y.chargesVariables || !y.chargesVariables[op.key]) { log.status = 'skip'; log.reason = 'clé absente'; break; }
        if (op.periode !== 'mois' && op.periode !== 'semaine') { log.status = 'skip'; log.reason = 'periode invalide'; break; }
        const old = y.chargesVariables[op.key].periode;
        y.chargesVariables[op.key].periode = op.periode;
        log.key = op.key; log.avant = old; log.apres = op.periode; break;
      }

      // ═══ ÉPARGNE ═══
      case 'set_epargne': {
        if (!y || !y.epargne || !y.epargne[op.key]) { log.status = 'skip'; log.reason = 'année ou clé absente'; break; }
        const old = y.epargne[op.key].valeur;
        y.epargne[op.key].valeur = Number(op.valeur);
        log.key = op.key; log.avant = old; log.apres = Number(op.valeur); break;
      }
      case 'add_epargne': {
        if (!y) { log.status = 'skip'; log.reason = 'année absente'; break; }
        if (!y.epargne) y.epargne = {};
        if (y.epargne[op.key]) { log.status = 'skip'; log.reason = 'clé existe déjà'; break; }
        y.epargne[op.key] = { label: String(op.label || op.key), valeur: Number(op.valeur || 0) };
        log.key = op.key; log.created = true; break;
      }
      case 'remove_epargne': {
        if (!y || !y.epargne || !y.epargne[op.key]) { log.status = 'skip'; log.reason = 'clé absente'; break; }
        delete y.epargne[op.key]; log.key = op.key; log.removed = true; break;
      }

      // ═══ DÉPENSES PONCTUELLES ═══
      case 'add_depense_ponctuelle': {
        if (!y) { log.status = 'skip'; log.reason = 'année absente'; break; }
        if (!Array.isArray(y.depensesIrregulieres)) y.depensesIrregulieres = [];
        const id = Date.now() + Math.floor(Math.random() * 1000);
        y.depensesIrregulieres.push({ id, mois: Number(op.mois), annee: a, nom: String(op.nom), montant: Number(op.montant), paye: false, montantPaye: 0 });
        log.id = id; log.nom = op.nom; log.montant = Number(op.montant); break;
      }
      case 'remove_depense_ponctuelle': {
        if (!y) { log.status = 'skip'; log.reason = 'année absente'; break; }
        if (!Array.isArray(y.depensesIrregulieres)) y.depensesIrregulieres = [];
        const before = y.depensesIrregulieres.length;
        const byId = op.id != null;
        const byName = op.nom != null;
        y.depensesIrregulieres = y.depensesIrregulieres.filter(d => {
          if (byId && Number(d.id) === Number(op.id)) return false;
          if (byName && String(d.nom).toLowerCase().trim() === String(op.nom).toLowerCase().trim()) return false;
          return true;
        });
        log.critere = byId ? ('id=' + op.id) : ('nom=' + op.nom);
        log.supprimees = before - y.depensesIrregulieres.length; break;
      }
      case 'update_depense_ponctuelle': {
        if (!y || !Array.isArray(y.depensesIrregulieres)) { log.status = 'skip'; log.reason = 'année absente'; break; }
        const target = y.depensesIrregulieres.find(d => Number(d.id) === Number(op.id));
        if (!target) { log.status = 'skip'; log.reason = 'id introuvable'; break; }
        if (op.montant != null) target.montant = Number(op.montant);
        if (op.mois != null) target.mois = Number(op.mois);
        if (op.annee != null) target.annee = Number(op.annee);
        if (op.nom != null) target.nom = String(op.nom);
        log.id = op.id; log.updated = true; break;
      }

      // ═══ SOLDES INITIAUX ═══
      case 'set_solde_initial': {
        if (!financeData.soldesInitiaux) financeData.soldesInitiaux = {};
        const allowed = ['courant','urgence','lt','bourse','moisActuel','anneeActuelle','semainesRestantes'];
        if (!allowed.includes(op.key)) { log.status = 'skip'; log.reason = 'clé non autorisée'; break; }
        const old = financeData.soldesInitiaux[op.key];
        financeData.soldesInitiaux[op.key] = Number(op.valeur);
        log.key = op.key; log.avant = old; log.apres = Number(op.valeur); break;
      }

      // ═══ ANNÉES ═══
      case 'clone_annee': {
        const src = financeData.donneesAnnuelles && financeData.donneesAnnuelles[op.depuis];
        if (!src) { log.status = 'skip'; log.reason = 'année source absente'; break; }
        if (financeData.donneesAnnuelles[op.vers]) { log.status = 'skip'; log.reason = 'année cible existe déjà'; break; }
        const cloned = JSON.parse(JSON.stringify(src));
        Object.values(cloned.chargesFixes || {}).forEach(f => { f.paye = false; f.montantPaye = 0; });
        Object.values(cloned.chargesVariables || {}).forEach(c => { if (c.details) c.details.forEach(d => { d.paye = false; d.montantPaye = 0; }); });
        (cloned.depensesIrregulieres || []).forEach(d => { d.paye = false; d.montantPaye = 0; d.annee = Number(op.vers); d.id = Date.now() + Math.floor(Math.random() * 1000); });
        financeData.donneesAnnuelles[op.vers] = cloned;
        log.depuis = op.depuis; log.vers = op.vers; log.created = true; break;
      }
      case 'delete_annee': {
        if (!financeData.donneesAnnuelles[op.annee]) { log.status = 'skip'; log.reason = 'année absente'; break; }
        delete financeData.donneesAnnuelles[op.annee];
        log.annee = op.annee; log.removed = true; break;
      }

      // ═══ PROJET STUDIO ═══
      case 'set_projet_studio': {
        if (!y) { log.status = 'skip'; log.reason = 'année absente'; break; }
        if (!y.projetStudio) y.projetStudio = {};
        const allowed = ['prixM2','surface','avance','taux','duree','taxSyndic','taxCouvertCredit','surplusCredit','assuranceMensuelle','travaux','epargneDispo'];
        if (!allowed.includes(op.key)) { log.status = 'skip'; log.reason = 'champ non autorisé'; break; }
        const old = y.projetStudio[op.key];
        y.projetStudio[op.key] = Number(op.valeur);
        log.key = op.key; log.avant = old; log.apres = Number(op.valeur); break;
      }

      default:
        log.status = 'skip'; log.reason = 'type inconnu: ' + op.type;
    }
  } catch (e) {
    log.status = 'error'; log.reason = e.message;
  }
  return log;
}

// ── Applique toutes les ops ──
const log = [];
for (const op of operations) {
  log.push(applyOp(financeData, op, anneeTarget));
}

if (!financeData.donneesAnnuelles || typeof financeData.donneesAnnuelles !== 'object') {
  return JSON.stringify({ error: 'Structure finance_data invalide après application des opérations.' });
}

// ── POST save_data.php ──
const url = 'https://n8n.beau.ink/finance/save_data.php';
try {
  const resp = await this.helpers.httpRequest({
    method: 'POST',
    url,
    body: financeData,
    json: true,
    headers: { 'Content-Type': 'application/json' },
    timeout: 15000
  });
  return JSON.stringify({
    status: 'ok',
    committed: true,
    operations_count: operations.length,
    operations_log: log,
    server_response: resp
  });
} catch (e) {
  return JSON.stringify({ status: 'error', committed: false, error: e.message, operations_log: log });
}

// ════════════════════════════════════════════════════════
// FORMAT FOR TELEGRAM — convertit HTML riche → texte Telegram
// Telegram parse_mode=HTML supporte uniquement :
//   <b>, <strong>, <i>, <em>, <u>, <s>, <code>, <pre>, <a href="">
// On supprime le reste, on convertit <br>/<li>/<ul> en texte plat.
// ════════════════════════════════════════════════════════
const item = $input.first().json;
let html = item.output || item.text || '';

if (typeof html !== 'string') html = String(html);

const text = html
  // Sauts de ligne
  .replace(/<br\s*\/?>/gi, '\n')
  .replace(/<\/p>\s*<p[^>]*>/gi, '\n\n')
  .replace(/<\/?p[^>]*>/gi, '')
  // Listes
  .replace(/<\/li>/gi, '\n')
  .replace(/<li[^>]*>/gi, '• ')
  .replace(/<\/?ul[^>]*>/gi, '\n')
  .replace(/<\/?ol[^>]*>/gi, '\n')
  // Séparateurs
  .replace(/<hr\s*\/?>/gi, '\n———\n')
  // Spans (couleurs) : on garde le contenu, on supprime les balises
  .replace(/<\/?span[^>]*>/gi, '')
  .replace(/<\/?div[^>]*>/gi, '\n')
  // Normalise <strong>→<b> et <em>→<i> (Telegram supporte les 2 mais on canonise)
  .replace(/<strong>/gi, '<b>').replace(/<\/strong>/gi, '</b>')
  .replace(/<em>/gi, '<i>').replace(/<\/em>/gi, '</i>')
  // Strip toutes les autres balises non supportées par Telegram
  .replace(/<(?!\/?(b|i|u|s|code|pre|a)\b)[^>]+>/gi, '')
  // Décode entités HTML courantes
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"')
  .replace(/&#39;/g, "'")
  // Nettoie multi-lignes vides
  .replace(/\n{3,}/g, '\n\n')
  .trim();

return [{
  json: {
    telegram_text: text,
    chat_id: $('Telegram Trigger').first().json.message.chat.id
  }
}];
